import{_ as t,o as a,c as n,a2 as i}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Chapter 10: Conversation State Machines","description":"Designing conversation state management with message history, token counting, compaction, persistence, and cost optimization for long-running agent sessions.","frontmatter":{"title":"Chapter 10: Conversation State Machines","description":"Designing conversation state management with message history, token counting, compaction, persistence, and cost optimization for long-running agent sessions."},"headers":[],"relativePath":"learn/linear/10-conversation-state-machines/index.md","filePath":"learn/linear/10-conversation-state-machines/index.md"}'),s={name:"learn/linear/10-conversation-state-machines/index.md"};function o(r,e,l,c,h,m){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="conversation-state-machines" tabindex="-1">Conversation State Machines <a class="header-anchor" href="#conversation-state-machines" aria-label="Permalink to &quot;Conversation State Machines&quot;">​</a></h1><p>This chapter addresses one of the most complex challenges in building a coding agent: managing conversation state over time. Unlike a simple chatbot with short exchanges, a coding agent maintains long-running sessions where the conversation history grows to include thousands of messages spanning code changes, tool outputs, error logs, and reasoning traces. Managing this state correctly is essential for the agent to remain coherent, stay within context window limits, and avoid runaway costs.</p><p>We model conversation as a state machine where each message transition can trigger context window evaluation, compaction decisions, and persistence operations. You will learn how to count tokens accurately across different models, implement compaction algorithms that preserve the most relevant context while shedding redundant information, and design summarization techniques that maintain semantic fidelity. These are the same problems that production agents like Claude Code must solve.</p><p>The chapter also explores advanced conversation patterns: branching conversations for exploring alternatives, multi-agent conversations where multiple LLMs collaborate, and session persistence that allows conversations to resume across process restarts. We close with cost optimization strategies that help users manage API spending without sacrificing conversation quality.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Model conversation as a state machine with well-defined transitions and invariants</li><li>Design message history data structures that efficiently support insertion, truncation, and search</li><li>Implement accurate token counting using tiktoken and model-specific tokenizers</li><li>Build compaction algorithms that respect context window limits while preserving essential context</li><li>Persist conversation sessions to disk with storage formats that support efficient resume and search</li><li>Apply cost optimization techniques including message pruning, caching, and model routing</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/10-conversation-state-machines/01-conversation-as-state.html">Conversation as State</a></li><li><a href="/linear/10-conversation-state-machines/02-message-history-design.html">Message History Design</a></li><li><a href="/linear/10-conversation-state-machines/03-token-counting-strategies.html">Token Counting Strategies</a></li><li><a href="/linear/10-conversation-state-machines/04-context-window-management.html">Context Window Management</a></li><li><a href="/linear/10-conversation-state-machines/05-compaction-algorithms.html">Compaction Algorithms</a></li><li><a href="/linear/10-conversation-state-machines/06-summarization-techniques.html">Summarization Techniques</a></li><li><a href="/linear/10-conversation-state-machines/07-session-persistence.html">Session Persistence</a></li><li><a href="/linear/10-conversation-state-machines/08-storage-formats.html">Storage Formats</a></li><li><a href="/linear/10-conversation-state-machines/09-branching-conversations.html">Branching Conversations</a></li><li><a href="/linear/10-conversation-state-machines/10-multi-agent-conversations.html">Multi Agent Conversations</a></li><li><a href="/linear/10-conversation-state-machines/11-system-prompt-evolution.html">System Prompt Evolution</a></li><li><a href="/linear/10-conversation-state-machines/12-memory-patterns.html">Memory Patterns</a></li><li><a href="/linear/10-conversation-state-machines/13-cost-optimization.html">Cost Optimization</a></li><li><a href="/linear/10-conversation-state-machines/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4 (agentic loop with conversation state and the fundamental request/response cycle)</li><li>Chapter 3 (understanding of tokens, context windows, and message formats)</li><li>Familiarity with Rust enums, structs, and trait-based design from Chapter 2</li></ul>',10)])])}const u=t(s,[["render",o]]);export{g as __pageData,u as default};
